import React, { useState } from 'react';
import axios from 'axios';

const StartPage = ({ onQuizStart }) => {
  const [formData, setFormData] = useState({
    teamName: '',
    teamLeaderName: '',
    teamLeaderEmail: ''
  });

  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState('');

  const validateForm = () => {
    const newErrors = {};

    if (!formData.teamName.trim()) {
      newErrors.teamName = 'Team name is required';
    }

    if (!formData.teamLeaderName.trim()) {
      newErrors.teamLeaderName = 'Team leader name is required';
    }

    if (!formData.teamLeaderEmail) {
      newErrors.teamLeaderEmail = 'Email is required';
    } else if (!/\S+@\S+\.\S+/.test(formData.teamLeaderEmail)) {
      newErrors.teamLeaderEmail = 'Invalid email format';
    }

    return newErrors;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    // Clear error for this field
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const newErrors = validateForm();
    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    setLoading(true);
    setApiError('');

    try {
      const response = await axios.post('http://localhost:8000/start-quiz', {
        team_name: formData.teamName,
        team_leader_name: formData.teamLeaderName,
        team_leader_email: formData.teamLeaderEmail
      });

      onQuizStart(response.data.quiz_id, formData);

    } catch (error) {
      console.error('Failed to start quiz:', error);
      setApiError(
        error.response?.data?.detail || 
        'Failed to start quiz. Please try again.'
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container">
      <div className="card">
        <h1>Online Quiz</h1>
        <p style={{ textAlign: 'center', color: '#718096', marginBottom: '30px' }}>
          25 Questions • 30 Minutes • One Chance
        </p>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="teamName">Team Name</label>
            <input
              type="text"
              id="teamName"
              name="teamName"
              value={formData.teamName}
              onChange={handleChange}
              className={errors.teamName ? 'error' : ''}
              placeholder="Enter your team name"
              disabled={loading}
            />
            {errors.teamName && (
              <div className="error-message">{errors.teamName}</div>
            )}
          </div>

          <div className="form-group">
            <label htmlFor="teamLeaderName">Team Leader Name</label>
            <input
              type="text"
              id="teamLeaderName"
              name="teamLeaderName"
              value={formData.teamLeaderName}
              onChange={handleChange}
              className={errors.teamLeaderName ? 'error' : ''}
              placeholder="Enter team leader's name"
              disabled={loading}
            />
            {errors.teamLeaderName && (
              <div className="error-message">{errors.teamLeaderName}</div>
            )}
          </div>

          <div className="form-group">
            <label htmlFor="teamLeaderEmail">Team Leader Email</label>
            <input
              type="email"
              id="teamLeaderEmail"
              name="teamLeaderEmail"
              value={formData.teamLeaderEmail}
              onChange={handleChange}
              className={errors.teamLeaderEmail ? 'error' : ''}
              placeholder="Enter email address"
              disabled={loading}
            />
            {errors.teamLeaderEmail && (
              <div className="error-message">{errors.teamLeaderEmail}</div>
            )}
          </div>

          {apiError && (
            <div className="error-message" style={{ marginBottom: '20px' }}>
              {apiError}
            </div>
          )}

          <button 
            type="submit" 
            className="btn"
            disabled={loading}
          >
            {loading ? 'Starting...' : 'Start Quiz'}
          </button>
        </form>

        <div style={{ marginTop: '20px', textAlign: 'center', color: '#718096', fontSize: '0.9rem' }}>
          <p>⚠️ Please note: Once started, you cannot pause or go back.</p>
        </div>
      </div>
    </div>
  );
};

export default StartPage;
